SELECT sun_radiation_intensity 
FROM sun_radiation_data 
ORDER BY sun_radiation_intensity DESC;

SELECT SUM(d.temperature) AS total_temperature
FROM datasets d
WHERE d.data_type_id = (SELECT type_id FROM data_types WHERE type_name = 'temperature');

SELECT MAX(sun_radiation_intensity) AS max_radiation_intensity
FROM sun_radiation_data
WHERE timestamp >= datetime('now', '-10 minutes');

SELECT dataset_id
FROM mse_values
WHERE mse_value = (SELECT MAX(mse_value) FROM mse_values);
